def fit_data(X,Y):
#Main SQANN loop
1-now=1 # layer now
while True:
ssig, collision = sample.collection(X,Y,1-now)
if ssg is 'no_more_data':
break
elif ssg is 'collision':
1_c = collision['collided_layer']
for 1.j from 1_c+1 to 1_now+1:
return_index(1.j)
kp = collision['perpetrator_index']
push_node(kp,X[kp,:],Y[kp],1.c)
1-now = 1.c
1-now+=1
